cat << 'EOF' > /home/user/myproject/books/books.go
package books

import (
	"context"
)

type Book struct {
	ID     int    `json:"id"`
	Title  string `json:"title"`
	Author string `json:"author"`
}

type AddBookParams struct {
	Title  string `json:"title"`
	Author string `json:"author"`
}

//encore:api public method=POST path=/books
func AddBook(ctx context.Context, p *AddBookParams) (*Book, error) {
	var b Book
	err := db.QueryRow(ctx, `
		INSERT INTO books (title, author)
		VALUES ($1, $2)
		RETURNING id, title, author
	`, p.Title, p.Author).Scan(&b.ID, &b.Title, &b.Author)
	if err != nil {
		return nil, err
	}
	return &b, nil
}

type ListBooksResponse struct {
	Books []*Book `json:"books"`
}

//encore:api public method=GET path=/books
func ListBooks(ctx context.Context) (*ListBooksResponse, error) {
	rows, err := db.Query(ctx, `
		SELECT id, title, author FROM books
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var books []*Book
	for rows.Next() {
		var b Book
		if err := rows.Scan(&b.ID, &b.Title, &b.Author); err != nil {
			return nil, err
		}
		books = append(books, &b)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

    if books == nil {
        books = []*Book{}
    }

	return &ListBooksResponse{Books: books}, nil
}
